                | "PT" | "RE" | "RU" | "SE" | "SJ" | "SK" | "SM" | "VA",
            ) => 4,
            _ => 1,
        };

        let first_day = locale
            .first_day_of_week_extension()
            .unwrap_or(default_first_day);

        Self {
            first_day,
            weekend_start,
            weekend_end,
            minimal_days_in_first_week,
        }
    }
}

