+    /// Handles keydown on a segment.
+    pub fn on_segment_keydown(
+        &self,
+        kind: DateSegmentKind,
+        data: &KeyboardEventData,
+        shift: bool,
+        dir: Direction,
+    ) {
+        let is_rtl = dir.is_rtl();
+
+        match data.key {
+            KeyboardKey::ArrowUp => (self.send)(Event::IncrementSegment { kind }),
