+        if let Some(value) = segment.value {
+            attrs.set(HtmlAttr::Aria(AriaAttr::ValueNow), value.to_string());
+            attrs.set(HtmlAttr::Aria(AriaAttr::ValueText), &segment.text);
+        } else {
